use sample_mflix
``````sh
db.createView(
  "moviesWithEmbeddings",
  "embedded_movies",
  [
    {
      "$match": {
        "$expr": {
          "$ne": [
            {
              "$type": "$plot_embedding_voyage_3_large"
            },
            "missing"
          ]
        }
      }
    }
  ]
)
``````sh
db.moviesWithEmbeddings.createSearchIndex(
  "embeddingsIndex",
  "vectorSearch",
  {
    "fields": [
      {
        "type": "vector",
        "numDimensions": 2048,
        "path": "plot_embedding_voyage_3_large",
        "similarity": "cosine"
      }
    ]
  }
)
```
